import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface RegionSales {
  name: string;
  salesTotal: number;
}

interface SalesData {
  regions: RegionSales[];
}

export default function Widget() {
  const salesData = response.data as SalesData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'dark' ? '#1E293B' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: theme === 'dark' ? '#F8FAFC' : '#1F2937', mb: 1 }}>
            Sales by Region
          </Typography>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              series={[
                {
                  data: salesData.regions.map(region => ({
                    id: region.name,
                    value: region.salesTotal,
                    color: region.name === 'Asia' ? primaryColor : accentColor,
                  })),
                },
              ]}
              sx={{
                '& .MuiPieElement-root': {
                  stroke: theme === 'dark' ? '#1E293B' : '#FFFFFF',
                  strokeWidth: 1,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {salesData.regions.map(region => (
              <Typography
                key={region.name}
                variant="body2"
                sx={{
                  color: theme === 'dark' ? '#F8FAFC' : '#1F2937',
                  fontSize: '12px',
                  fontWeight: 500,
                }}
              >
                {region.name}: ${region.salesTotal.toLocaleString()}
              </Typography>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
